class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string res;
        while (a > 0 || b > 0) {
            if (a > b) {
                if (a > 1 && res.size() > 0 && res.back() == 'a') {
                    res += 'b';
                    b--;
                } else {
                    res += 'a';
                    a--;
                }
            } else if (b > a) {
                if (b > 1 && res.size() > 0 && res.back() == 'b') {
                    res += 'a';
                    a--;
                } else {
                    res += 'b';
                    b--;
                }
            } else {
                if (res.size() > 0 && res.back() == 'a') {
                    res += 'b';
                    b--;
                } else {
                    res += 'a';
                    a--;
                }
            }
        }
        return res;
    }
};
```

